mapper.select:
SELECT review_id, user_number, store_id, category, review_content, rating, created_date, modified_date
FROM reviews
WHERE review_id = #{reviewId}

mapper.update:
UPDATE reviews
SET review_content = #{reviewContent},
    rating         = #{rating},
    category       = #{category}
WHERE review_id    = #{reviewId}
  AND user_number  = #{userNumber}

mapper.select:
SELECT COUNT(*)
FROM bookmark
WHERE user_number = #{userNumber}
  AND storeId     = #{storeId}

mapper.delete:
DELETE FROM bookmark
WHERE user_number = #{userNumber}
  AND storeId     = #{storeId}
